+class MatchEachExpression {
+  constructor(
+    private entries: readonly Entry[],
+    private hasInput: boolean,
+    private input: unknown
+  ) {}
+
+  with(...args: any[]): MatchEachExpression {
+    return new MatchEachExpression([...this.entries, { args }], this.hasInput, this.input);
+  }
+
+  when(predicate: (value: unknown) => unknown, handler: (value: unknown) => unknown): MatchEachExpression {
+    return this.with(predicate, handler, MatchEachExpression.whenMarker);
+  }
+
+  tap(callback: (result: unknown) => unknown): MatchEachExpression {
+    return new MatchEachExpression([...this.entries, { tap: callback }], this.hasInput, this.input);
+  }
+
+  otherwise(handler: (value: unknown) => unknown): unknown[] {
+    const results = this.evaluate(this.input);
+    return results.length ? results : [handler(this.input)];
+  }
+
+  exhaustive(unexpectedValueHandler = defaultCatcher): unknown[] {
+    const results = this.evaluate(this.input);
+    return results.length ? results : [unexpectedValueHandler(this.input)];
+  }
+
+  run(): unknown[] {
+    return this.exhaustive();
+  }
+
+  returnType(): this { return this; }
+  narrow(): this { return this; }
+
+  toFunction(): (input: unknown) => unknown[] {
+    return (input) => {
+      const results = this.evaluate(input);
+      if (!results.length) throw new NonExhaustiveError(input);
+      return results;
+    };
+  }
